// WF-REFUND 1: 입력 검증
// Body: { settlement_id, cancel_reason }
var body = $input.first().json.body || $input.first().json;
var settlementId = (body.settlement_id || '').trim();
var cancelReason = (body.cancel_reason || '고객 취소 요청').trim();

if (!settlementId) {
  throw new Error('[WF-REFUND] settlement_id is required');
}

return [{ json: { settlementId: settlementId, cancelReason: cancelReason } }];

// WF-REFUND 2: 취소 가능 여부 분류
// _action: 'already_cancelled' | 'cancel_no_deduct' | 'cancel_with_deduct' | 'manual_required'
var findResult = $input.first().json;
var validateData = $('Validate Input').first().json;
var list = findResult.list || [];

if (list.length === 0) {
  throw new Error('[WF-REFUND] Settlement not found for order_id: ' + validateData.orderId);
}

var s = list[0];
var status = s.status || '';
var classDateStr = s.class_date || '';

// 수강일 vs 오늘 비교
var classDate = null;
if (classDateStr) {
  classDate = new Date(classDateStr);
  classDate.setHours(0, 0, 0, 0);
}
var today = new Date();
today.setHours(0, 0, 0, 0);

// 취소 액션 결정
var _action;
if (status === 'CANCELLED') {
  _action = 'already_cancelled';
} else if (status === 'PENDING_SETTLEMENT') {
  // 적립금 미지급 상태 → 단순 취소
  _action = 'cancel_no_deduct';
} else if (status === 'COMPLETED') {
  if (classDate && classDate >= today) {
    // 수강일 미도래 → 적립금 환수 후 취소
    _action = 'cancel_with_deduct';
  } else {
    // 수강일 경과 → 관리자 수동 처리
    _action = 'manual_required';
  }
} else {
  // FAILED 등 → 관리자 수동
  _action = 'manual_required';
}

// partner_code: Links(배열) 또는 문자열 양쪽 대응
var partnerCode = s.partner_code;
if (Array.isArray(partnerCode) && partnerCode.length > 0) {
  partnerCode = partnerCode[0].partner_code || partnerCode[0].Title || String(partnerCode[0]);
} else if (!partnerCode) {
  partnerCode = '';
} else {
  partnerCode = String(partnerCode);
}

return [{
  json: {
    _action: _action,
    _settlementId: s.settlement_id || '',
    nocodbId: s.Id || s.id || '',
    _memberId: s.member_id || '',
    _partnerCode: partnerCode,
    _reserveAmount: Number(s.reserve_amount) || 0,
    _orderAmount: Number(s.order_amount) || 0,
    _classId: s.class_id || '',
    _classDate: classDateStr,
    _studentName: s.student_name || '수강생',
    _studentEmail: s.student_email || '',
    _cancelReason: validateData.cancelReason,
    _orderId: validateData.orderId,
    _currentStatus: status
  }
}];

// 적립금 차감 결과 확인
// 실패해도 취소는 계속 진행 (관리자 텔레그램으로 알림)
var deductResult = $input.first().json;
var _deductSuccess = false;
var _deductNote = '';

try {
  if (deductResult.return_code === '0000' && deductResult.datas && deductResult.datas[0]) {
    var r = deductResult.datas[0];
    _deductSuccess = (r.result === true || r.result === 1 || r.result === '1');
    if (!_deductSuccess) {
      _deductNote = Array.isArray(r.message) ? r.message.join(', ') : (r.message || '적립금 차감 실패');
    }
  } else {
    _deductNote = 'return_code=' + (deductResult.return_code || 'unknown');
  }
} catch(e) {
  _deductNote = '파싱 오류: ' + (e.message || '');
}

return [{ json: { _deductSuccess: _deductSuccess, _deductNote: _deductNote } }];

